+            },
+            interceptor: None,
+        };
+
+        let taxonomy_codes = ["timeout", "denied", "io", "invalid_request", "internal"];
+        let legacy_codes = ["tool_error", "SHUTDOWN", "CANCELLED", "cancelled"];
+
+        // Denied-by-policy (exec denied).
+        let denied_req = crate::extensions_js::HostcallRequest {
