+        if let HostcallOutcome::Error { code, .. } = &outcome {
+            assert!(
+                taxonomy_codes.contains(&code.as_str()),
+                "denied-by-policy produced non-taxonomy code: {code}"
+            );
+            for legacy in &legacy_codes {
+                assert_ne!(code, legacy, "emitted legacy code: {code}");
+            }
+        }
